class Solution {
public:
    long long minimumCost(string s) {
        long long cost = 0;
        int n = s.size();
        for (int i = 1; i < n; i += 2) {
            if (s[i] != s[i - 1]) {
                cost += min(i + 1, n - i);
            }
        }
        return cost;
    }
};
```
